import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";const i=JSON.parse(`{"title":"开发者指南","description":"我们的社区编写的开发者指南，涵盖许多主题，从创建一个模组和设置你的开发环境，一直到渲染、网络通信、数据生成等。","frontmatter":{"title":"开发者指南","description":"我们的社区编写的开发者指南，涵盖许多主题，从创建一个模组和设置你的开发环境，一直到渲染、网络通信、数据生成等。","authors":["IMB11","its-miroma","itsmiir"],"authors-nogithub":["basil4088"],"files":[]},"headers":[],"relativePath":"zh_cn/develop/index.md","filePath":"translated/zh_cn/develop/index.md","lastUpdated":1771183440000}`);var a={name:`zh_cn/develop/index.md`};function o(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">开发者指南 <a class="header-anchor" href="#h1" aria-label="Permalink to “开发者指南”">​</a></h1><p>Fabric 是一款适用于 Minecraft：Java 版的轻量级模组工具链，设计简洁易用， 让开发者能够对原版游戏进行修改（“模组”），添加新功能或更改现有机制。</p><p>本文档将指导你使用 Fabric 进行模组开发，从<a href="./getting-started/creating-a-project">创建第一个模组</a>和<a href="./getting-started/setting-up">设置环境</a>，到<a href="./rendering/basic-concepts">渲染</a>、<a href="./networking">网络</a>、<a href="./data-generation/setup">数据生成</a>等高级主题，应有尽有。</p><p>完整的页面列表请查看侧边栏。</p><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>如果你需要，包含本文档所有代码的完整有效模组可在 <a href="https://github.com/FabricMC/fabric-docs/tree/main/reference/latest" target="_blank" rel="noreferrer">Github 中的 <code>/reference</code> 文件夹</a>中找到。</p></div><h2 id="prerequisites" tabindex="-1">前置条件 <a class="header-anchor" href="#prerequisites" aria-label="Permalink to “前置条件”">​</a></h2><p>在开始使用 Fabric 编写模组之前，你需要对 Java 开发以及面向对象编程有一定了解。</p><p>以下是一些也许能帮助你熟悉 Java 和 OOP （面向对象编程）的资源：</p><ul><li><a href="https://www.w3schools.com/java/" target="_blank" rel="noreferrer">W3: Java Tutorials</a></li><li><a href="https://www.codecademy.com/learn/learn-java" target="_blank" rel="noreferrer">Codecademy: Learn Java</a></li><li><a href="https://www.w3schools.com/java/java_oop.asp" target="_blank" rel="noreferrer">W3: Java OOP</a></li><li><a href="https://medium.com/@Adekola_Olawale/beginners-guide-to-object-oriented-programming-a94601ea2fbd" target="_blank" rel="noreferrer">Medium: Introduction to OOP</a></li></ul><h2 id="what-does-fabric-offer" tabindex="-1">Fabric 能提供什么？ <a class="header-anchor" href="#what-does-fabric-offer" aria-label="Permalink to “Fabric 能提供什么？”">​</a></h2><p>Fabric 项目主要由三个核心组件组成：</p><ul><li><strong>Fabric Loader</strong>：一个灵活且跨平台的模组加载器，主要面向《Minecraft：Java 版》</li><li><strong>Fabric API</strong>：一套供模组开发者在创作模组时使用的配套 API 和工具集</li><li><strong>Fabric Loom</strong>：<a href="https://gradle.org/" target="_blank" rel="noreferrer">Gradle</a> 插件，让开发者能够轻松开发和调试模组</li></ul><h3 id="what-does-fabric-api-offer" tabindex="-1">Fabric API 能提供什么？ <a class="header-anchor" href="#what-does-fabric-api-offer" aria-label="Permalink to “Fabric API 能提供什么？”">​</a></h3><p>Fabric API 提供了一系列构建在原版功能之上的 API，可以进行高级或简单的开发。</p><p>例如，它提供了新的钩子、事件、实用工具（例如传递访问加宽器）、对内部注册表（例如可堆肥物品注册表）的访问等等。</p>`,15)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};